import type { Program, Session } from "@prisma/client";
import { prisma } from "../../config/database.js";
import type { TenantId } from "../../types/tenant.js";

export async function assertProgramOwnedByTenant(
  tenantId: TenantId,
  programId: string
): Promise<Program | null> {
  return prisma.program.findFirst({
    where: { id: programId, tenantId: tenantId as string }
  });
}

export async function listSessionsForProgram(
  tenantId: TenantId,
  programId: string
): Promise<Session[]> {
  return prisma.session.findMany({
    where: {
      tenantId: tenantId as string,
      programId
    },
    orderBy: { position: "asc" }
  });
}

export async function getSessionById(
  tenantId: TenantId,
  id: string
): Promise<Session | null> {
  return prisma.session.findFirst({
    where: { id, tenantId: tenantId as string }
  });
}

export async function nextPosition(
  tenantId: TenantId,
  programId: string
): Promise<number> {
  const agg = await prisma.session.aggregate({
    where: { tenantId: tenantId as string, programId },
    _max: { position: true }
  });
  return (agg._max.position ?? -1) + 1;
}

export async function createSession(
  tenantId: TenantId,
  data: {
    programId: string;
    title: string;
    durationSeconds: number;
    position: number;
    instructorName: string;
    tags: string[];
    mediaUrl: string | null | undefined;
    mediaType: string | null | undefined;
  }
): Promise<Session> {
  return prisma.session.create({
    data: {
      tenantId: tenantId as string,
      programId: data.programId,
      title: data.title,
      durationSeconds: data.durationSeconds,
      position: data.position,
      instructorName: data.instructorName,
      tags: data.tags,
      mediaUrl: data.mediaUrl ?? undefined,
      mediaType: data.mediaType ?? undefined
    }
  });
}

export async function updateSession(
  tenantId: TenantId,
  id: string,
  data: {
    title?: string;
    durationSeconds?: number;
    position?: number;
    instructorName?: string;
    tags?: string[];
    mediaUrl?: string | null;
    mediaType?: string | null;
  }
): Promise<Session | null> {
  const existing = await getSessionById(tenantId, id);
  if (!existing) {
    return null;
  }
  return prisma.session.update({
    where: { id },
    data: {
      ...(data.title !== undefined ? { title: data.title } : {}),
      ...(data.durationSeconds !== undefined
        ? { durationSeconds: data.durationSeconds }
        : {}),
      ...(data.position !== undefined ? { position: data.position } : {}),
      ...(data.instructorName !== undefined
        ? { instructorName: data.instructorName }
        : {}),
      ...(data.tags !== undefined ? { tags: data.tags } : {}),
      ...(data.mediaUrl !== undefined ? { mediaUrl: data.mediaUrl } : {}),
      ...(data.mediaType !== undefined ? { mediaType: data.mediaType } : {})
    }
  });
}

export async function deleteSession(
  tenantId: TenantId,
  id: string
): Promise<boolean> {
  const result = await prisma.session.deleteMany({
    where: { id, tenantId: tenantId as string }
  });
  return result.count > 0;
}

import { Prisma } from "@prisma/client";
import { HttpError } from "../../lib/httpError.js";
import { appendAuditLog } from "../../lib/auditWriter.js";
import { prisma } from "../../config/database.js";
import type { TenantId } from "../../types/tenant.js";
import type {
  CreateSessionBody,
  ReorderSessionsBody,
  UpdateSessionBody
} from "./schemas.js";
import * as repo from "./sessions.repository.js";

const POSITION_CONFLICT_MESSAGE =
  "Position is already in use for this program. Choose another position or use the reorder endpoint.";

function throwIfSessionPositionConflict(err: unknown): void {
  if (
    err instanceof Prisma.PrismaClientKnownRequestError &&
    err.code === "P2002"
  ) {
    throw new HttpError(409, POSITION_CONFLICT_MESSAGE, "position_conflict");
  }
}

export async function listSessions(tenantId: TenantId, programId: string) {
  const program = await repo.assertProgramOwnedByTenant(tenantId, programId);
  if (!program) {
    throw new HttpError(404, "Program not found", "not_found");
  }
  return repo.listSessionsForProgram(tenantId, programId);
}

export async function getSession(tenantId: TenantId, id: string) {
  const s = await repo.getSessionById(tenantId, id);
  if (!s) {
    throw new HttpError(404, "Session not found", "not_found");
  }
  return s;
}

export async function createSession(
  tenantId: TenantId,
  actorId: string,
  body: CreateSessionBody
) {
  const program = await repo.assertProgramOwnedByTenant(tenantId, body.programId);
  if (!program) {
    throw new HttpError(404, "Program not found", "not_found");
  }

  const position =
    body.position !== undefined
      ? body.position
      : await repo.nextPosition(tenantId, body.programId);

  try {
    const session = await repo.createSession(tenantId, {
      programId: body.programId,
      title: body.title,
      durationSeconds: body.durationSeconds,
      position,
      instructorName: body.instructorName,
      tags: body.tags,
      mediaUrl: body.mediaUrl,
      mediaType: body.mediaType
    });

    await appendAuditLog({
      tenantId,
      actorId,
      action: "session.created",
      targetType: "session",
      targetId: session.id,
      metadata: { programId: body.programId, title: session.title }
    });

    return session;
  } catch (err) {
    throwIfSessionPositionConflict(err);
    throw err;
  }
}

export async function updateSession(
  tenantId: TenantId,
  actorId: string,
  id: string,
  body: UpdateSessionBody
) {
  try {
    const session = await repo.updateSession(tenantId, id, body);
    if (!session) {
      throw new HttpError(404, "Session not found", "not_found");
    }
    await appendAuditLog({
      tenantId,
      actorId,
      action: "session.updated",
      targetType: "session",
      targetId: id
    });
    return session;
  } catch (err) {
    throwIfSessionPositionConflict(err);
    throw err;
  }
}

export async function removeSession(
  tenantId: TenantId,
  actorId: string,
  id: string
) {
  const ok = await repo.deleteSession(tenantId, id);
  if (!ok) {
    throw new HttpError(404, "Session not found", "not_found");
  }
  await appendAuditLog({
    tenantId,
    actorId,
    action: "session.deleted",
    targetType: "session",
    targetId: id
  });
}

export async function reorderSessions(
  tenantId: TenantId,
  actorId: string,
  body: ReorderSessionsBody
) {
  const program = await repo.assertProgramOwnedByTenant(tenantId, body.programId);
  if (!program) {
    throw new HttpError(404, "Program not found", "not_found");
  }

  const existing = await repo.listSessionsForProgram(tenantId, body.programId);
  const existingIds = new Set(existing.map((s) => s.id));
  const uniq = new Set(body.orderedSessionIds);
  if (uniq.size !== body.orderedSessionIds.length) {
    throw new HttpError(
      400,
      "orderedSessionIds must not contain duplicates",
      "validation_error"
    );
  }
  if (existing.length !== body.orderedSessionIds.length) {
    throw new HttpError(
      400,
      "orderedSessionIds must list every session in the program",
      "validation_error"
    );
  }
  for (const id of body.orderedSessionIds) {
    if (!existingIds.has(id)) {
      throw new HttpError(
        400,
        "Unknown session id for this program",
        "validation_error"
      );
    }
  }

  await prisma.$transaction(async (tx) => {
    const offset = 1_000_000;
    for (let i = 0; i < body.orderedSessionIds.length; i++) {
      const sid = body.orderedSessionIds[i];
      await tx.session.updateMany({
        where: {
          id: sid,
          tenantId: tenantId as string,
          programId: body.programId
        },
        data: { position: offset + i }
      });
    }
    for (let i = 0; i < body.orderedSessionIds.length; i++) {
      const sid = body.orderedSessionIds[i];
      await tx.session.updateMany({
        where: {
          id: sid,
          tenantId: tenantId as string,
          programId: body.programId
        },
        data: { position: i }
      });
    }
  });

  await appendAuditLog({
    tenantId,
    actorId,
    action: "session.reordered",
    targetType: "program",
    targetId: body.programId
  });

  return repo.listSessionsForProgram(tenantId, body.programId);
}

import type { RequestHandler } from "express";
import { HttpError } from "../../lib/httpError.js";
import {
  createSessionBodySchema,
  reorderSessionsBodySchema,
  updateSessionBodySchema
} from "./schemas.js";
import * as sessionsService from "./sessions.service.js";

function requireTenantContext(req: Parameters<RequestHandler>[0]) {
  const tenantId = req.tenantId;
  const creatorId = req.creatorId;
  if (!tenantId || !creatorId) {
    return null;
  }
  return { tenantId, creatorId };
}

export const list: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const programId =
      typeof req.query.programId === "string" ? req.query.programId : "";
    if (!programId) {
      next(
        new HttpError(400, "query programId is required", "validation_error")
      );
      return;
    }
    const sessions = await sessionsService.listSessions(ctx.tenantId, programId);
    res.json({ sessions });
  } catch (e) {
    next(e);
  }
};

export const getById: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const session = await sessionsService.getSession(
      ctx.tenantId,
      req.params.id
    );
    res.json(session);
  } catch (e) {
    next(e);
  }
};

export const create: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const parsed = createSessionBodySchema.safeParse(req.body);
    if (!parsed.success) {
      next(new HttpError(400, "Invalid request body", "validation_error"));
      return;
    }
    const session = await sessionsService.createSession(
      ctx.tenantId,
      ctx.creatorId,
      parsed.data
    );
    res.status(201).json(session);
  } catch (e) {
    next(e);
  }
};

export const update: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const parsed = updateSessionBodySchema.safeParse(req.body);
    if (!parsed.success) {
      next(new HttpError(400, "Invalid request body", "validation_error"));
      return;
    }
    const session = await sessionsService.updateSession(
      ctx.tenantId,
      ctx.creatorId,
      req.params.id,
      parsed.data
    );
    res.json(session);
  } catch (e) {
    next(e);
  }
};

export const remove: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    await sessionsService.removeSession(
      ctx.tenantId,
      ctx.creatorId,
      req.params.id
    );
    res.status(204).send();
  } catch (e) {
    next(e);
  }
};

export const reorder: RequestHandler = async (req, res, next) => {
  try {
    const ctx = requireTenantContext(req);
    if (!ctx) {
      next(new HttpError(401, "Unauthorized", "unauthorized"));
      return;
    }
    const parsed = reorderSessionsBodySchema.safeParse(req.body);
    if (!parsed.success) {
      next(new HttpError(400, "Invalid request body", "validation_error"));
      return;
    }
    const sessions = await sessionsService.reorderSessions(
      ctx.tenantId,
      ctx.creatorId,
      parsed.data
    );
    res.json({ sessions });
  } catch (e) {
    next(e);
  }
};

import { Router, type IRouter } from "express";
import * as controller from "./sessions.controller.js";

export const sessionsRouter: IRouter = Router();

sessionsRouter.get("/", controller.list);
sessionsRouter.post("/reorder", controller.reorder);
sessionsRouter.post("/", controller.create);
sessionsRouter.get("/:id", controller.getById);
sessionsRouter.patch("/:id", controller.update);
sessionsRouter.delete("/:id", controller.remove);

